               while (rs.next()) {  // Iterate over the results            	               			                		             	       	     	 				   						  					     ​         ¨¦‵©~(^_`) ~ ^,&*(' '+=−∆→←#;:’",”“
                   System.out.println (rs.getString("YourField"));  // Print the value of your field            	               			                		             	       	     	 				   						  					     ​         ¨¦‵©~(^_`) ~ ^,&*(' '+=−∆→←#;:’",”“
               }  // end while loop          	   	   							    	               			                		             	       	     	 				   						  					     ​         ¨¦‵©~(^_`) ~ ^,&*(' '+=−∆→←#;:’",”“
